import{_ as i,o as t,c as s,ae as a}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"ByteCodeViewer","description":"https://github.com/Konloch/bytecode-viewer/releases","frontmatter":{"description":"https://github.com/Konloch/bytecode-viewer/releases"},"headers":[],"relativePath":"pen-testing/decompilers/bytecodeviewer.md","filePath":"pen-testing/decompilers/bytecodeviewer.md"}'),l={name:"pen-testing/decompilers/bytecodeviewer.md"};function r(o,e,n,h,p,d){return t(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="bytecodeviewer" tabindex="-1">ByteCodeViewer <a class="header-anchor" href="#bytecodeviewer" aria-label="Permalink to &quot;ByteCodeViewer&quot;">​</a></h1><h2 id="bytecode-viewer" tabindex="-1">Bytecode Viewer <a href="#firstheading" id="firstheading"></a> <a class="header-anchor" href="#bytecode-viewer" aria-label="Permalink to &quot;Bytecode Viewer &lt;a href=&quot;#firstheading&quot; id=&quot;firstheading&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p><a href="https://github.com/Konloch/bytecode-viewer/releases" target="_blank" rel="noreferrer"><mark style="color:yellow;">Download here</mark></a></p><p><a href="https://github.com/Konloch/bytecode-viewer/releases" target="_blank" rel="noreferrer">https://github.com/Konloch/bytecode-viewer/releases</a></p><table tabindex="0"><thead><tr><th>A Java Reverse Engineering &amp; Debugging Suite</th><th></th></tr></thead><tbody><tr><td>Author</td><td>Kalen (<a href="http://konloch.me/" target="_blank" rel="noreferrer">Konloch</a>) Kinloch</td></tr><tr><td>Homepage</td><td><a href="https://bytecodeviewer.com/" target="_blank" rel="noreferrer">BytecodeViewer.com</a></td></tr><tr><td>Download</td><td><a href="https://github.com/konloch/bytecode-viewer/releases" target="_blank" rel="noreferrer">Releases</a></td></tr><tr><td>Source Code</td><td><a href="https://github.com/konloch/bytecode-viewer" target="_blank" rel="noreferrer">Github</a></td></tr><tr><td>Issues</td><td><a href="https://github.com/konloch/bytecode-viewer/issues" target="_blank" rel="noreferrer">Issues</a></td></tr></tbody></table><p>I’ll break this post into two sections, the first is the functional part of BCV, the interface, settings, tools, features etc. The second part will contain how to utilize the BCV API/Plugin System to develop your own plugins (if you do decide to create a plugin, please decide to open source it so I can add it to <a href="https://github.com/Konloch/bytecode-viewer/tree/master/plugins" target="_blank" rel="noreferrer">https://github.com/Konloch/bytecode-viewer/tree/master/plugins</a>).</p><br><h3 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h3><p> [<a href="https://wiki.bytecode.club/Bytecode_Viewer" target="_blank" rel="noreferrer">hide</a>] </p><ul><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#Functionality" target="_blank" rel="noreferrer">1Functionality</a><ul><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#File" target="_blank" rel="noreferrer">1.1File</a></li><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#View_Panes" target="_blank" rel="noreferrer">1.2View Panes</a></li><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#Settings" target="_blank" rel="noreferrer">1.3Settings</a></li><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#Plugins" target="_blank" rel="noreferrer">1.4Plugins</a></li></ul></li><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#API" target="_blank" rel="noreferrer">2API</a><ul><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#Exceptions" target="_blank" rel="noreferrer">2.1Exceptions</a></li><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#Plugin_Console" target="_blank" rel="noreferrer">2.2Plugin Console</a></li><li><a href="https://wiki.bytecode.club/Bytecode_Viewer#Bytecode_Hooks" target="_blank" rel="noreferrer">2.3Bytecode Hooks</a></li></ul></li></ul><h3 id="functionality" tabindex="-1">Functionality <a class="header-anchor" href="#functionality" aria-label="Permalink to &quot;Functionality&quot;">​</a></h3><p>Bytecode Viewer (BCV) was designed to be extremely user and beginner friendly, because of this almost everything is accessible through an interface, settings, tools, etc. This means if you give BCV a try you should get the gist of it can do, however for those who don&#39;t want to run BCV until they&#39;re convinced they should use it, below is a complete list of features BCV has, and what they do.</p><p><strong>File</strong></p><ul><li>Add (Ctrl + O) – If you add a jar/zip BCV will unzip it, if you add an APK or DEX file, BCV will run dex2jar then run the jar input process.</li><li>New Workspace (Ctrl + N) – It clears the opened jars/resources.</li><li>Run (Ctrl + R) – Runs the classfiles you’ve loaded into BCV in a secure sandboxed JVM instance that you can fully debug.</li><li>Compile (Ctrl + T) – Tries to compile all of the editable panes you’ve selected, if it’s Java it’ll compile with Ranino. Krakatau and *Smali use their own assemblers.</li><li>Save As Jar – Export the class files and loaded resources as a runnable Jar file.</li><li>Save As DEX – Run jar2dex and export the Classfiles as DEX.</li><li>Save Files As – Save all the Classfiles and resources as a zip.</li><li>Save Java File As – Save the currently opened decompiled Classfile.</li><li>Save Java Files As – Save all of the decompiled Classfiles as a zip.</li><li>Recent Files – Last 25 files/directories you’ve opened with BCV.</li><li>About – A small information window about BCV.</li><li>Exit – Closes BCV.</li></ul><p><strong>View Panes</strong></p><ul><li>Editable – Defines if that viewing pane will be editable.</li><li>None – Nothing will be displayed.</li><li>Procyon – Decompiles with Procyon decompiler.</li><li>CFR – Decompilers with CFR decompiler.</li><li>FernFlower – Decompiles with FernFlower decompiler.</li><li>JD-GUI – Decompiles with JD-GUI decompiler.</li><li>Krakatau Java – Decompiles with Krakatau decompiler.</li><li>Krakatau Bytecode – Disassembles with Krakatau disassembler.</li><li>Smali – Disassembles with Smali.</li><li>Bytecode – Decompiles the Bytecode via CFIDE. Not Editable.</li><li>Hexcode – Shows the classfile in a hex viewer. Not Editable.</li></ul><p><strong>Settings</strong></p><ul><li>Compile On Save – If selected whenever you do one of the File&gt;Save * functions it will try to compile before it saves.</li><li>Compile On Refresh – If selected whenever you press refresh it compile before it reloads the resource/class.</li><li>Update Check – If selected it queries <a href="https://github.com/Konloch/bytecode-viewer" target="_blank" rel="noreferrer">https://github.com/Konloch/bytecode-viewer</a> to ensure you’ve got the latest version.</li><li>Refresh On View Change – If selected whenever you change an option in the View Panes it will refresh the currently opened resources/class.</li><li>Decode APK Resources – If selected whenever you add an APK, it will first run APKTool.jar to decode the resources.</li><li>Set Python 2.7 Executable – Set the Python 2.7 executable if you want Krakatau decompiler/disassembler/assembler to work.</li><li>Set JRE RT Library – Set the JRE RT library for Krakatau decompiler.</li></ul><p><strong>Plugins</strong></p><ul><li>Open Plugin – Open a .java plugin created for BCV.</li><li>Recent Plugins – Last 25 plugins you’ve opened with BCV.</li><li>Code Sequence Diagram – Builds a crude code sequence diagram for the classfile that’s currently opened.</li><li>Malicious Code Scanner – Allows you to define what to search for, and outputs what it found.</li><li>Show Main Methods – Detects and outputs all of the public static void main(String[]) functions.</li><li>Show All Strings – Grabs then outputs all of the strings in every classfile.</li><li>Replace Strings – Allows you to do a simple permanent .replace on the classfile strings, very useful for URL swapping.</li><li>Allatori String Decrypter – Decrypts the Allatori obfuscated/encrypted strings.</li><li>ZKM String Decrypter – Decrypts the ZKM obfuscated/encrypted strings.</li><li>ZStringArray String Decrypter – Decrypts the ZStringArray obfuscated/encrypted strings.</li></ul><h3 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h3><p>The API is designed for people who wish to utilize the plugin system for BCV, or use the hook system that File&gt;Run (EZ-Injection) provides. The external plugin system is very simple, it takes a .java file that extends the abstract Plugin class. Compiles that class then loads it into memory and invokes the execute(ArrayList&lt;ClassNode&gt;).</p><p>Before you start making a plugin, take a look at the Java docs for the API then some example source code.</p><p>The principal behind the plugin system is very simple, once the plugin is loaded into memory it calls on the execute function with a ClassNode ArrayList. From here we can completely handle this using ASM. However since we still want to interact with BCV itself or interact with the user I’ve added some hooks and small classes to make this easy for the plugin authors.</p><p><strong>Exceptions</strong></p><p>All exceptions that are unexpected and require the user to report them should be handled like this:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">try</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">   ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">catch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Exception</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> e</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    new</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> the</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bytecode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">club</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bytecodeviewer</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">api</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ExceptionUI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">e</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;author@email.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Plugin Console</strong></p><p>All messages to the user that aren’t alerts should use the Plugin Console an example of this is:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> PluginConsole</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> gui</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> PluginConsole</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Skeleton&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> gui</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setVisible</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> gui</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appendText</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;executed skeleton&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Those two things are what you really need for most plugins, if you need anything else take a look at <a href="https://the.bytecode.club/docs/bytecode-viewer/the/bytecode/club/bytecodeviewer/api/BytecodeViewer.html" target="_blank" rel="noreferrer">https://the.bytecode.club/docs/bytecode-viewer/the/bytecode/club/bytecodeviewer/api/BytecodeViewer.html</a>.</p><p><strong>Bytecode Hooks</strong></p><p>BCV has a built in tool to assist in hooks, this section will be expanded later.</p><p><a href="https://wiki.bytecode.club/Special:Categories" target="_blank" rel="noreferrer">Categories</a>: </p><ul><li><a href="https://wiki.bytecode.club/index.php?title=Category:Pages_with_syntax_highlighting_errors&amp;action=edit&amp;redlink=1" target="_blank" rel="noreferrer">Pages with syntax highlighting errors</a></li><li><a href="https://wiki.bytecode.club/Category:Tools" target="_blank" rel="noreferrer">Tools</a></li><li><a href="https://wiki.bytecode.club/Category:Java" target="_blank" rel="noreferrer">Java</a></li><li><a href="https://wiki.bytecode.club/Category:Android" target="_blank" rel="noreferrer">Android</a></li><li><a href="https://wiki.bytecode.club/Category:Reverse_Engineering" target="_blank" rel="noreferrer">Reverse Engineering</a></li></ul>`,35)])])}const k=i(l,[["render",r]]);export{u as __pageData,k as default};
